 1	import * as React from 'react';
 2	import { useTranslation } from 'react-i18next';
 3	import { PageSection } from '@patternfly/react-core';
 4	import { taskRunFilterReducer } from '../../utils/pipeline-filter-reducer';
 5	import TaskRunDetailsSection from './TaskRunDetailsSection';
 6	import { TaskRunModel } from '../../../models';
 7	import ResultsList from './ResultList';
 8	import { TaskRunKind } from '../../../types';
 9	import './TaskRunDetails.scss';
10	
11	export interface TaskRunDetailsProps {
12	  obj: TaskRunKind;
13	}
14	
15	const TaskRunDetails: React.FC<TaskRunDetailsProps> = ({ obj: taskRun }) => {
16	  const { t } = useTranslation('plugin__pipelines-console-plugin');
17	
18	  return (
19	    <>
20	      <PageSection isFilled variant="light">
21	        <TaskRunDetailsSection taskRun={taskRun} />
22	      </PageSection>
23	      {taskRun?.status?.taskResults || taskRun?.status?.results ? (
24	        <PageSection isFilled variant="light">
25	          <ResultsList
26	            results={taskRun.status?.taskResults || taskRun.status?.results}
27	            resourceName={t(TaskRunModel.labelKey)}
28	            status={taskRunFilterReducer(taskRun)}
29	          />
30	        </PageSection>
31	      ) : null}
32	    </>
33	  );
34	};
35	
36	export default TaskRunDetails;

